 1	import * as React from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { Button } from '@patternfly/react-core';
 5	
 6	import { GettingStartedLink } from '../types';
 7	
 8	export type GettingStartedMoreLinkContentProps = {
 9	  moreLink: GettingStartedLink;
10	};
11	
12	const GettingStartedMoreLinkContent: React.FC<GettingStartedMoreLinkContentProps> = ({
13	  moreLink,
14	}) => {
15	  if (!moreLink) {
16	    return null;
17	  }
18	
19	  if (moreLink?.onClick) {
20	    const handleClick = moreLink.onClick;
21	    return (
22	      <Button data-test={`item ${moreLink.id}`} isInline onClick={handleClick} variant="link">
23	        {moreLink.title}
24	      </Button>
25	    );
26	  }
27	
28	  if (moreLink?.external) {
29	    return (
30	      <a
31	        className="co-external-link"
32	        data-test={`item ${moreLink.id}`}
33	        href={moreLink.href}
34	        rel="noopener noreferrer"
35	        target="_blank"
36	      >
37	        {moreLink.title}
38	      </a>
39	    );
40	  }
41	
42	  return (
43	    <Link data-test={`item ${moreLink.id}`} to={moreLink.href}>
44	      {moreLink.title}
45	    </Link>
46	  );
47	};
48	
49	export default GettingStartedMoreLinkContent;

